import{_ as t,C as o,o as a,c as i,a5 as r,b as l,w as n,a as g,E as d,a4 as p}from"./chunks/framework.gGRxziV4.js";const B=JSON.parse('{"title":"争论与未来","description":"","frontmatter":{},"headers":[],"relativePath":"01-Harness工程核心原则/06-争论与未来.md","filePath":"01-Harness工程核心原则/06-争论与未来.md","lastUpdated":1774181700000}'),h={name:"01-Harness工程核心原则/06-争论与未来.md"};function u(A,e,c,m,b,E){const s=o("Mermaid");return a(),i("div",null,[e[1]||(e[1]=r('<h1 id="争论与未来" tabindex="-1">争论与未来 <a class="header-anchor" href="#争论与未来" aria-label="Permalink to &quot;争论与未来&quot;">​</a></h1><p><strong>Harness Engineering 核心原则 · 第六章</strong></p><blockquote><p>模型是马，Harness 是挽具。模型决定你能跑多快，Harness 决定你能不能把力量真正拉到车上。</p></blockquote><p>前五章建立了 Harness Engineering 的完整体系：范式转移、感官系统、成本结构、操作系统视角、实战调优方法。本章回到一个根本性的问题——<strong>Harness 到底有没有长期价值？</strong></p><p>AI 工程圈对此有激烈的争论。两种观点，一个工具光谱，以及最终的调和。</p><hr><h2 id="一、big-model-vs-big-harness" tabindex="-1">一、Big Model vs Big Harness <a class="header-anchor" href="#一、big-model-vs-big-harness" aria-label="Permalink to &quot;一、Big Model vs Big Harness&quot;">​</a></h2><p>一个 Agent 表现得好，到底是因为底层基座模型的能力极强，还是因为它外围包裹的工程 Harness 搭得极好？</p><p>这就像金融圈的经典争论：一个交易员一年给公司赚了 300 万美金，到底是因为他个人操盘能力极其厉害，还是因为他坐在了高盛的交易席位上？</p><h3 id="big-model-派" tabindex="-1">Big Model 派 <a class="header-anchor" href="#big-model-派" aria-label="Permalink to &quot;Big Model 派&quot;">​</a></h3><p>以 Claude Code 为代表的大模型派认为：Harness 很可能只是一个过渡产物。Claude Code 的 Harness 被刻意设计成<strong>最薄的一层 wrapper</strong>，主创们的主要工作就是尽量不要干预模型，让模型自己发挥全部能力。</p><p>一些测试数据似乎支持这种观点。在 Scale AI 的 SWE Atlas 编程基准测试中，Claude 的 Opus 4.6 在 Claude Code 的 Harness 下表现好一点点，但 GPT-5.2 反而在通用的 SWE Agent Harness 下表现稍微好一点——分差非常小，基本都在误差范围之内。</p><p>高阶推理模型核心作者 Noam Brown 说得更直接：在推理模型出现之前，为了让 GPT-4 表现出类似推理的能力，工程师在外围写了大量复杂的重试逻辑和 Prompt。但现在底层的 reasoning model 自己就能完成很多推理步骤——<strong>如果还强行塞进去一堆复杂脚手架，反而可能拖慢模型的表现。</strong></p><blockquote><p>Big Model 派的核心论断：<strong>模型越强，需要的套壳代码就越薄。</strong> 一旦基座模型跨代升级，你辛苦写的几万行编排代码可能很快就会变成历史遗产。</p></blockquote><h3 id="big-harness-派" tabindex="-1">Big Harness 派 <a class="header-anchor" href="#big-harness-派" aria-label="Permalink to &quot;Big Harness 派&quot;">​</a></h3><p>LlamaIndex 创始人 Jerry Liu 的观点完全不同。他认为今天我们已经拥有很强的模型和很多优秀的工具，但企业真正难解决的问题<strong>从来不是模型够不够聪明</strong>，而是你有没有能力把业务里的上下文正确地组织并喂给模型。</p><p>举个最直观的例子：如果你想用 Claude Code 去自动处理公司客户流程，你必须先花大量时间把业务类型、流程规范、权限规则全部写成清晰的文档。一份标准 SOP 光是把规则描述清楚，往往就要反复修改几个小时——这件事模型很难自动帮你完成。</p><p>Jerry Liu 的结论：未来几乎所有 AI 产品本质上都在做两件事——<strong>提供上下文</strong>和<strong>提供工作流</strong>。</p><h3 id="一个有趣的实验" tabindex="-1">一个有趣的实验 <a class="header-anchor" href="#一个有趣的实验" aria-label="Permalink to &quot;一个有趣的实验&quot;">​</a></h3><p>一位开发者维护着一个开源编程 Agent。有一天下午他只改了一件事——没有换模型，也没有重新训练任何东西，只是<strong>调整了 Harness 里编辑代码的工具格式</strong>。结果 15 个主流大模型在编程基准测试里全部获得了明显提升。</p><p>他的结论非常形象：<strong>&quot;模型出问题很多时候不是因为他理解不了任务，而是因为他没有合适的语言来表达自己。你一直在怪飞行员，但其实是起落架坏了。&quot;</strong></p><h3 id="调和-model-×-harness" tabindex="-1">调和：Model × Harness <a class="header-anchor" href="#调和-model-×-harness" aria-label="Permalink to &quot;调和：Model × Harness&quot;">​</a></h3><p>AI 圈一直有一种调和派说法叫 Compound AI——模型有价值，系统工程也有价值。但这次情况可能有所不同。随着 Cursor 估值突破 500 亿美元，随着越来越多企业 Agent 真正落地，&quot;所有套壳工程最终都会消失&quot;的判断正在被市场挑战。欧洲 AI Eng Europe 大会上已经正式开设了全球第一个 Harness Engineering 专赛道。</p><p>未来的竞争很可能不是 Model <strong>VS</strong> Harness，而是 <strong>Model × Harness</strong>。两者相乘，共同决定最终的表现。</p>',24)),(a(),l(p,null,{default:n(()=>[d(s,{id:"mermaid-74",class:"mermaid",graph:"quadrantChart%0A%20%20%20%20title%20Model%20vs%20Harness%20%E5%85%89%E8%B0%B1%0A%20%20%20%20x-axis%20%22Harness%20%E8%96%84%22%20--%3E%20%22Harness%20%E5%8E%9A%22%0A%20%20%20%20y-axis%20%22Model%20%E5%BC%B1%22%20--%3E%20%22Model%20%E5%BC%BA%22%0A%20%20%20%20quadrant-1%20%22%E5%BC%BA%E6%A8%A1%E5%9E%8B%2B%E5%8E%9AHarness%22%0A%20%20%20%20quadrant-2%20%22%E5%BC%BA%E6%A8%A1%E5%9E%8B%2B%E8%96%84Harness%22%0A%20%20%20%20quadrant-3%20%22%E5%BC%B1%E6%A8%A1%E5%9E%8B%2B%E8%96%84Harness%22%0A%20%20%20%20quadrant-4%20%22%E5%BC%B1%E6%A8%A1%E5%9E%8B%2B%E5%8E%9AHarness%22%0A%20%20%20%20%22Claude%20Code%22%3A%20%5B0.2%2C%200.85%5D%0A%20%20%20%20%22Deep%20Agents%22%3A%20%5B0.85%2C%200.75%5D%0A%20%20%20%20%22%E6%97%A9%E6%9C%9F%20GPT-4%20%2B%20%E5%A4%8D%E6%9D%82%E7%AE%A1%E9%81%93%22%3A%20%5B0.9%2C%200.3%5D%0A%20%20%20%20%22%E7%BA%AF%20API%20%E8%B0%83%E7%94%A8%22%3A%20%5B0.1%2C%200.15%5D%0A"})]),fallback:n(()=>[...e[0]||(e[0]=[g(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=r(`<blockquote><p>💡 <strong>图解：</strong> 强模型不需要厚 Harness？但企业难题从来不是模型聪明度——未来的竞争是 Model × Harness 的乘法效应。</p></blockquote><hr><h2 id="二、framework-vs-harness-工具光谱" tabindex="-1">二、Framework vs Harness：工具光谱 <a class="header-anchor" href="#二、framework-vs-harness-工具光谱" aria-label="Permalink to &quot;二、Framework vs Harness：工具光谱&quot;">​</a></h2><p>很多人学 AI 开发的第一步是去学 LangChain，学完发现还有 Crew AI、AutoGen、LangGraph……就像打地鼠，层出不穷。但真正重要的问题根本不在这里——<strong>没有人告诉你这些工具压根儿不是同一类东西。</strong> 有的是 Framework，有的是 Harness。</p><h3 id="光谱-从左到右" tabindex="-1">光谱：从左到右 <a class="header-anchor" href="#光谱-从左到右" aria-label="Permalink to &quot;光谱：从左到右&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>纯代码 ←——————→ Framework ←——————→ Harness</span></span>
<span class="line"><span>(最左)            (中间)            (最右)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>纯代码</strong>——没有任何封装，直接调大模型 API，手动管理所有状态。灵活性最大，但所有麻烦都得自己扛。</p><p><strong>Framework</strong>（LangChain、Crew AI）——给你封装好的组件、工具接口、任务调度、角色分工，帮你屏蔽底层通信的麻烦。但系统怎么设计还是你说了算，用什么模型你决定，怎么存记忆你决定。就像去宜家买家具——板材和螺丝钉都给了，拼成什么是你的事。</p><p><strong>Harness</strong>（OpenAI Codex）——不给你零件，直接给你一套完整的系统。填一个 API 密钥就能跑，记忆怎么存、出错怎么重试，全都替你决定好了。就像买了一辆原厂精调好的跑车——给油就走，代价是不能动它的内部逻辑。Harness 是用控制权换上限速度。</p><h3 id="langchain-自己的扩张" tabindex="-1">LangChain 自己的扩张 <a class="header-anchor" href="#langchain-自己的扩张" aria-label="Permalink to &quot;LangChain 自己的扩张&quot;">​</a></h3><p>有意思的是，LangChain 自己也在向右扩张。他们把技术栈分成了三层：最底层 LangChain（Framework）、中间层 LangGraph（执行引擎）、最外层 Deep Agents（Harness）。一家公司把整条光谱都吃下来了。</p><h3 id="选型指南" tabindex="-1">选型指南 <a class="header-anchor" href="#选型指南" aria-label="Permalink to &quot;选型指南&quot;">​</a></h3><p>选工具之前，先问自己一个问题：<strong>你是要长期掌控每一行代码，还是要赶进度拿现成套件直接交付？</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">需求</th><th style="text-align:left;">选择</th></tr></thead><tbody><tr><td style="text-align:left;">长期掌控、深度定制</td><td style="text-align:left;">Framework</td></tr><tr><td style="text-align:left;">快速交付、开箱即用</td><td style="text-align:left;">Harness</td></tr><tr><td style="text-align:left;">极简场景、完全自主</td><td style="text-align:left;">纯代码</td></tr></tbody></table><h3 id="anthropic-的忠告" tabindex="-1">Anthropic 的忠告 <a class="header-anchor" href="#anthropic-的忠告" aria-label="Permalink to &quot;Anthropic 的忠告&quot;">​</a></h3><p>Anthropic 在 <em>Building Effective Agents</em> 里明确说过：做 Agent 要慎用复杂框架。框架的黑盒一旦出错，调试会很痛苦，而且调用太方便容易让团队陷入过度工程化。很多时候<strong>直接写几行代码连大模型 API，反而更快更稳</strong>。</p><hr><h2 id="三、回到-harness-engineering" tabindex="-1">三、回到 Harness Engineering <a class="header-anchor" href="#三、回到-harness-engineering" aria-label="Permalink to &quot;三、回到 Harness Engineering&quot;">​</a></h2><p>争论归争论，有一个事实越来越清晰：当代码开始由 Agent 生成，仓库就不再只是人类协作空间——它变成了一个<strong>机器认知系统</strong>。</p><p>在这个系统里，Harness 不是锦上添花的框架，而是操作系统级别的基础设施。它管理上下文、约束行为、捕获崩溃数据、构建反馈闭环。</p><p>不管 Big Model 派和 Big Harness 派怎么争论，有一点双方都会同意：<strong>你改进系统的能力上限，完全取决于你验证输出有多容易。</strong> 而验证，恰恰是 Harness 的核心功能。</p><blockquote><p><strong>唯一可靠的方法仍然是不断实验，观察结果，持续调整——Seeing Like an Agent。</strong></p></blockquote><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ol><li><strong>Big Model 派</strong>——Harness 是过渡产物，模型越强套壳越薄，一旦基座升级编排代码变遗产</li><li><strong>Big Harness 派</strong>——企业难题不在模型聪明度，在上下文组织；未来 AI 产品本质做两件事：提供上下文 + 提供工作流</li><li><strong>调和：Model × Harness</strong>——两者相乘共同决定最终表现，市场正在验证 Harness 的长期价值</li><li><strong>工具光谱</strong>——纯代码（灵活）→ Framework（宜家家具）→ Harness（原厂跑车），搞清区别才能正确选型</li><li><strong>核心共识</strong>——不管什么派，都同意&quot;验证输出有多容易&quot;决定了改进系统的上限</li></ol><hr><p><a href="./05-验证、工具与优化.html">← 上一章：验证、工具与优化</a> | <a href="./">返回目录 →</a></p><hr><p><a href="/Hermes-Engineering-ai-agent-/">← 返回首页</a> | <a href="/Hermes-Engineering-ai-agent-/02-上下文工程/">下一模块: 上下文工程 →</a></p>`,29))])}const q=t(h,[["render",u]]);export{B as __pageData,q as default};
